const e={title:"Black SIM Cards",description:"Black SIM cards, also known as 'black phone cards', refer to mobile phone cards (including wireless data cards) that have not been registered under a real name and are used by criminals for illegal activities. Since the implementation of phone real-name registration in September 2013, new users in China have largely completed real-name registration. However, due to lax enforcement and large existing stock, unregistered phone cards still number as many as 180 million, giving criminals opportunities to spread obscene content, commit telecommunications fraud, and organize terrorist activities. The main sources of black SIM cards are physical carrier cards, virtual carrier cards, and overseas phone cards.",references:[{title:"Black SIM Cards - Baidu Baike",link:"https://baike.baidu.com/item/%E7%94%B5%E8%AF%9D%E9%BB%91%E5%8D%A1/19710385?fr=aladdin"},{title:"China's Successful Anti-Fraud Practices",link:"https://www.mps.gov.cn/n2255079/n6865805/n7355741/n7355780/c8924764/content.html"}],avoidances:["A0016-003","A0024","A0029-001","A0044"],directCauseRisks:[],indirectSupportRisks:["R0003","R0003-003","R0003-004","R0005","R0005-001","R0030","R0030-001"]},t={AT0001:e,"AT0001-002":{title:"Modem Pool SIM Cards",description:"Black SIM cards used with a 'modem pool' — a network communication hardware device that enables simultaneous multi-number calling and bulk SMS sending.",references:[{title:"Modem Pool - Baidu Baike",link:"https://baike.baidu.com/item/%E7%8C%AB%E6%B1%A0?fromModule=lemma_search-box"}],avoidances:["A0024","A0016-003","A0044"],directCauseRisks:["R0024","R0053","R0084","R0110"],indirectSupportRisks:[]},"AT0001-003":{title:"Intercept SIM Cards",description:"SIM cards that, via malware or trojans, grant unauthorized control over a real user's SMS and verification code reception, typically sourced from intercept card platforms.",references:[{title:"The Current State of the SIM Card Black Market Under the 'Card-Cutting' Campaign",link:"https://zhuanlan.zhihu.com/p/640350477"}],avoidances:["A0024","A0016-003","A0023-001","A0048"],directCauseRisks:["R0005-001","R0030","R0030-001","R0030-007","R0089","R0092","R0098"],indirectSupportRisks:[]}},i=Object.freeze(Object.defineProperty({__proto__:null,AT0001:e,default:t},Symbol.toStringTag,{value:"Module"})),a={title:"Mobile Phone Emulator",description:"Also known as Android emulator or game emulator, it is a simulation program that can emulate an independent mobile phone system on a computer, enabling mobile apps to run on a PC. Originally designed for players to run mobile games on computers, some features have been exploited by gray/black market actors. The Root permissions provided by emulators enable value modification cheats, while the multi-instance feature is used by script studios for batch AFK farming and traffic inflation. Additionally, emulators can be used for batch account registration, simulated click traffic inflation, ranking manipulation, and other black/gray market activities. Some emulators support toggling Root permissions in real-time without restarting, further increasing detection difficulty.",references:[{title:"Game Emulators Become Cheat Accomplices, Gray Market Countermeasures Escalate",link:"https://baijiahao.baidu.com/s?id=1740234137947164618&wfr=spider&for=pc"}],avoidances:["A0010-001","A0021","A0059"],directCauseRisks:[],indirectSupportRisks:["R0001-002","R0003-003","R0005-001","R0012","R0016-001","R0034","R0050","R0088"]},o={AT0002:a},n=Object.freeze(Object.defineProperty({__proto__:null,AT0002:a,default:o},Symbol.toStringTag,{value:"Module"})),r={title:"Bulk Account Registration Tool",description:"An automation tool specifically designed for bulk registration of business accounts. Normal registration requires complex operations such as phone verification and CAPTCHA recognition, making it tedious to register even one account. However, gray/black market actors need large numbers of business accounts to support activities such as traffic inflation, deal abuse, and fraud. Bulk registration tools automate the registration process to quickly register large numbers of accounts. They are typically used in combination with SMS verification code platforms, CAPTCHA solving platforms, and proxy IP pools, forming a complete bulk registration industry chain that automates the entire process from obtaining phone numbers and solving CAPTCHAs to filling in registration information.",references:[{title:"OWASP Automated Threat: OAT-019 Account Creation",link:"https://owasp.org/www-project-automated-threats-to-web-applications/assets/oats/EN/OAT-019_Account_Creation.html"}],avoidances:["A0001","A0001-004","A0002","A0003","A0004","A0005","A0007","A0009","A0010","A0015","A0016","A0021","A0022","A0023","A0024","A0038","A0059"],directCauseRisks:["R0003-003","R0003-004","R0005-001","R0005-002","R0007-003","R0009"],indirectSupportRisks:["R0008","R0015","R0016","R0016-001","R0017-001","R0030","R0030-001"]},s={AT0003:r},l=Object.freeze(Object.defineProperty({__proto__:null,AT0003:r,default:s},Symbol.toStringTag,{value:"Module"})),c={title:"Modem Pool",description:"A modem pool (Modem POOL) is a telephone-based expansion device that connects a large number of modems together using special dial-up request access equipment, allowing simultaneous dial-up connections from multiple users. A modem pool can synchronously dial large numbers of user phone numbers, and fraudsters use it to improve the efficiency of their calling operations, making it a commonly used tool for telecom fraudsters. In the gray/black market domain, modem pools are also widely used to manage large numbers of SIM cards simultaneously, with supporting software enabling batch SMS receiving and sending. They are commonly used for batch spam account registration and deal abuse on major platforms. The phone cards used in modem pools are often non-real-name cheap cards obtained through black market channels. In recent years, modem pools are often used in conjunction with GOIP devices, and public security authorities have repeatedly dismantled modem pool operations in the 'Account Cutoff' campaign.",references:[{title:"Modem Pool - Baidu Baike",link:"https://baike.baidu.com/item/%E7%8C%AB%E6%B1%A0/1476300?fr=aladdin"},{title:"Police Reveal Seven Telecom Fraud Methods! Do You Know What a Modem Pool Is?",link:"https://baike.baidu.com/tashuo/browse/content?id=d4c4e5133318d337e28f6bd9"},{title:"Jiangsu Mobile Cracks Down on Modem Pools, Providing 6,363 GOIP Clues to Police",link:"http://js.people.com.cn/n2/2022/0613/c360303-35312923.html"}]},d={AT0004:c},u=Object.freeze(Object.defineProperty({__proto__:null,AT0004:c,default:d},Symbol.toStringTag,{value:"Module"})),p={title:"Web Scraping Tools",description:"Web crawlers, also known as 'web spiders' or 'web robots', are a network information collection technology in the internet era. They can be understood as computer programs that automatically simulate human operations online. These crawlers follow specific programs along certain paths, simulating manual operations to extract and store data from websites and applications. In the gray/black market domain, web scraping tools are widely used for data extraction, price monitoring, ticket grabbing, credential stuffing and account theft, and attacking computer systems, posing serious threats to enterprise data security and business order. With the development of big data and AI technology, web scraping tools have become increasingly intelligent, making anti-scraping countermeasures increasingly challenging.",references:[{title:"What Are Web Crawlers?",link:"https://baijiahao.baidu.com/s?id=⟦BANKCARD_6538E3AD⟧&wfr=spider&for=pc"},{title:"Scrapy Crawler Framework - Baidu Baike",link:"https://baike.baidu.com/item/scrapy/7914913?fr=aladdin"}]},m={AT0005:p},g=Object.freeze(Object.defineProperty({__proto__:null,AT0005:p,default:m},Symbol.toStringTag,{value:"Module"})),h={title:"SMS Verification Code Platform",description:"SMS verification code platforms are cloud service platforms that use virtual or physical phone numbers to receive SMS verification codes. Their principle is to connect phone numbers provided by card merchants to the platform, which then provides them to consumers. SMS verification codes are used in internet businesses to filter low-value users, based on the premise that phone numbers essentially implement real-name authentication. However, the gray/black market has developed SMS verification code platforms that stockpile large numbers of SIM cards to provide SMS sending and receiving services. Large platforms have been found to hold millions of SIM cards, while smaller ones hold tens of thousands. These platforms belong to the illegal gray industry that undermines internet real-name registration and has a severe impact on cybersecurity. In recent years, the platform model has evolved toward a decentralized 'group code receiving' model, where card merchants provide code receiving services directly to multiple black/gray market actors through social messaging tools, bypassing traditional platform account systems, reducing transaction costs and enhancing privacy, making enforcement even more difficult.",references:[{title:"What Do SMS Verification Code Platforms Do?",link:"https://zhidao.baidu.com/question/566282201955764244.html"}],avoidances:["A0016-003","A0029-001"],directCauseRisks:[],indirectSupportRisks:["R0003","R0003-003","R0005","R0005-001","R0005-002","R0009","R0016","R0016-001","R0030","R0030-001"]},f={AT0006:h},b=Object.freeze(Object.defineProperty({__proto__:null,AT0006:h,default:f},Symbol.toStringTag,{value:"Module"})),y={title:"Device Spoofing Tools",description:"Device spoofing tools are important tools relied upon by criminal gangs for large-scale operations. By modifying device parameters or forging device fingerprints, the same device can be identified as multiple different devices, thereby bypassing business risk controls. The core functions of device spoofing tools include modifying IMEI, IMSI, hardware serial numbers, MAC addresses, and other device identifiers, as well as the 'one-click new device' feature that quickly simulates device parameters from different manufacturers. Technically, device spoofing tools can use frameworks like Xposed and tools like Frida Hook to intercept and tamper with system calls without modifying APKs, and there are also Root-free spoofing solutions. Device spoofing tools are commonly used for batch account registration, batch account farming, bypassing device bans, and other scenarios. Some advanced tools also support one-click backup and restore functions, enabling quick switching and operation of multiple accounts on a single device.",references:[{title:"Fraud Tool 'Device Modification Software'",link:"https://zhuanlan.zhihu.com/p/391039941"},{title:"Xposed - A framework service that affects program execution (modifies the system) without modifying APK",link:"https://www.oschina.net/p/xposed?hmsr=aladdin1e1"},{title:"Frida - A convenient and easy-to-use cross-platform Hook tool",link:"https://frida.re/"}]},k={AT0007:y},A=Object.freeze(Object.defineProperty({__proto__:null,AT0007:y,default:k},Symbol.toStringTag,{value:"Module"})),v={title:"CAPTCHA Solving Platform",description:"A platform that provides CAPTCHA solving services through automated or human means. Simple character CAPTCHAs can no longer effectively block automated behavior and can be cracked using OCR recognition tools. More complex CAPTCHAs can be solved with high accuracy using deep learning (such as convolutional neural networks). For high-difficulty CAPTCHAs, human-powered solving platforms organize real people (commonly known as 'code slaves') to perform recognition and submit verification results. In recent years, with the development of AIGC technology, the confrontation between CAPTCHAs and solving platforms has entered a new AI-versus-AI stage — CAPTCHAs use generative adversarial networks to produce more complex adversarial examples, while solving platforms use deep learning models to continuously improve their cracking capabilities, forming a continuously escalating offensive-defensive game.",references:[{title:"Black Market Exposed: The Past and Present of CAPTCHA Solving Platforms",link:"https://www.jianshu.com/p/cd0c8251caa9"}]},w={AT0008:v},R=Object.freeze(Object.defineProperty({__proto__:null,AT0008:v,default:w},Symbol.toStringTag,{value:"Module"})),T={title:"Mass Control Systems",description:"A mass control system uses automated control integration technology to map multiple phone interfaces directly to a computer monitor, enabling one computer to control dozens or even hundreds of phones simultaneously. The system numbers each phone's interface on the control computer, corresponding to the same-numbered phone, achieving one-to-one phone operation control. Traditional mass control systems typically consist of software and hardware components, with the hardware including a control host, HUB, computer, and terminal phones, and the software using a control system with sub-control functionality operating in a local LAN environment. In recent years, mass control has evolved into a 'cloud control' model, where large numbers of phones are remotely controlled through cloud-based software without physical connections. A single computer can control tens of thousands of phones, commonly used for livestream traffic inflation, short video likes and comments, and other black/gray market activities.",references:[{title:"Basic Concepts of Mass Control Systems",link:"https://zhuanlan.zhihu.com/p/526198871"}],avoidances:["A0010","A0010-003","A0010-004","A0016-001","A0021","A0029-003","A0059"],directCauseRisks:[],indirectSupportRisks:["R0001-002","R0003-003","R0005-001","R0016-001","R0030-001","R0034","R0050","R0108"]},S={AT0009:T},_=Object.freeze(Object.defineProperty({__proto__:null,AT0009:T,default:S},Symbol.toStringTag,{value:"Module"})),C={title:"Dark Web",description:"The Dark Web refers to a part of the internet whose content is not indexed by traditional search engines and typically requires specific software or authorization to access. Websites on the dark web usually use highly anonymous browsers such as Tor (The Onion Router) to hide users' identities and locations. This anonymity makes the dark web a venue for activities requiring concealment, including illegal trading of drugs, hacking tools, cyberattack services, illegal weapons, and other illegal services.",references:[{title:"Dark Web - Baidu Baike",link:"https://baike.baidu.com/item/%E6%9A%97%E7%BD%91/8694490?fr=ge_ala"},{title:"Internet Organised Crime Threat Assessment (IOCTA)",link:"https://www.europol.europa.eu/publications-events/main-reports/iocta-report"}],avoidances:["A0016"],directCauseRisks:[],indirectSupportRisks:["R0011","R0028","R0043","R0044","R0060","R0062"]},P={AT0010:C},M=Object.freeze(Object.defineProperty({__proto__:null,AT0010:C,default:P},Symbol.toStringTag,{value:"Module"})),j={title:"Pre-installed Mobile Trojan Backdoor",description:"Attackers pre-install trojans primarily through two methods: first, through 'flashing' or APP (re-Root) methods, installing malware on phones before they reach users, such as RottenSys malware disguised as 'System WiFi Service'; second, some niche phone brand manufacturers collect user traffic through various means and even pre-install malware like StealthBot to compensate for their market share.",references:[{title:"360 Fully Exposes Mobile Phone Black Market: Wild Growth at Massive Scale",link:"https://attack.mitre.org/techniques/T1195/"}],avoidances:["A0010"],directCauseRisks:["R0003","R0005","R0005-001","R0005-002","R0008","R0008-001","R0030-001","R0035","R0036","R0043-001","R0045","R0067","R0083-001","R0112-001"],indirectSupportRisks:[]},O={AT0011:j},I=Object.freeze(Object.defineProperty({__proto__:null,AT0011:j,default:O},Symbol.toStringTag,{value:"Module"})),B={title:"Social Engineering Database",description:"A Social Engineering Database (SEDB) is a product of combining hacking with big data, where hackers integrate and analyze leaked user data and archive it centrally. It is a database query platform built from user data from major websites. Hackers obtain data packages through database breaches and credential stuffing that contain not only account passwords but also additional data from different industries. Information in social engineering databases often involves user privacy, making such sites illegal.",references:[{title:"Social Engineering Database - Baidu Baike",link:"https://baike.baidu.com/item/%E7%A4%BE%E5%B7%A5%E5%BA%93/1896113?fr=aladdin"},{title:"Ministry of Public Security: Crack Down on Crimes Infringing on Citizens' Personal Information",link:"https://www.mps.gov.cn/n2254314/n2254487/c5752336/content.html"}],avoidances:["A0007","A0016","A0024","A0011","A0012"],directCauseRisks:[],indirectSupportRisks:["R0011","R0032-001","R0040","R0083-001"]},x={AT0012:B},z=Object.freeze(Object.defineProperty({__proto__:null,AT0012:B,default:x},Symbol.toStringTag,{value:"Module"})),E={title:"Trojan Virus",description:"A computer trojan virus is a piece of malicious code with special functions hidden in a normal program. It is a backdoor program capable of destroying and deleting files, sending passwords, recording keystrokes, and attacking systems. Trojan programs appear harmless on the surface and may even be attractive to unsuspecting users, often hidden in games or graphics software. A complete trojan program generally consists of two parts: a server-side component and a controller-side component.",references:[{title:"Trojan Virus - Baidu Baike",link:"https://baike.baidu.com/item/%E6%9C%A8%E9%A9%AC%E7%97%85%E6%AF%92?fromModule=lemma_search-box"},{title:"Notice on the 'Dark Cloud' Trojan Program",link:"https://www.cert.org.cn/publish/main/10/2017/20170612141252046500561/20170612141252046500561_.html"}],avoidances:["A0010"],directCauseRisks:["R0008","R0008-001","R0032","R0067","R0083-001","R0112","R0112-001"],indirectSupportRisks:[]},D={AT0013:E},F=Object.freeze(Object.defineProperty({__proto__:null,AT0013:E,default:D},Symbol.toStringTag,{value:"Module"})),H={title:"Packet Capture Tools",description:"Packet capture tools are software that intercepts and inspects the contents of network data packets. Because they can capture all IP packets during data communication and perform layer-by-layer unpacking analysis, they have long been commonly used troubleshooting tools in traditional fixed-network maintenance. Popular packet capture software includes Wireshark, SnifferPro, Snoop, and Tcpdump. On the mobile side, tools like Fiddler, Charles, and mitmproxy are also widely used, often for mobile application interface analysis and man-in-the-middle (MITM) attacks. Black-grey market actors can use packet capture tools to obtain communication data between apps and servers, steal sensitive information, or reverse-engineer API interfaces to carry out automated attacks.",references:[{title:"Packet Capture Tools - Baidu Baike",link:"https://baike.baidu.com/item/%E6%8A%93%E5%8C%85%E5%B7%A5%E5%85%B7?fromModule=lemma_search-box"}],avoidances:["A0002","A0022","A0022-001","A0022-002","A0022-003","A0022-004","A0031","A0032","A0040"],directCauseRisks:["R0001","R0001-001","R0003-002","R0027","R0032-003","R0051-001","R0051-002"],indirectSupportRisks:["R0003","R0003-003","R0012","R0109"]},q={AT0014:H},W=Object.freeze(Object.defineProperty({__proto__:null,AT0014:H,default:q},Symbol.toStringTag,{value:"Module"})),L={title:"Debugging Tools",description:"A debugger is a computer program and tool used to debug other programs. It allows code to be inspected and selectively run in an instruction set simulator (ISS) for troubleshooting and debugging. Beyond debugging, a debugger is also frequently used as a tool for cracking software, such as bypassing copy protection, breaking serial number verification, and other software protection features.",references:[{title:"Debugging Tools - Woku Baike",link:"https://baike.baidu.com/item/%E8%B0%83%E8%AF%95%E5%B7%A5%E5%85%B7"}]},G={AT0015:L},U=Object.freeze(Object.defineProperty({__proto__:null,AT0015:L,default:G},Symbol.toStringTag,{value:"Module"})),K={title:"Cloud Phone",description:"A cloud phone applies cloud computing technology to network terminal services, implementing virtual phone functionality through cloud servers. Based on end-cloud integrated virtualization technology, cloud phones elastically adapt to user needs through cloud networking, security, and AI capabilities, offloading hardware resources and loading massive cloud applications on demand. Users can remotely control cloud phones in real time via video streaming, enabling Android native apps and mobile games to run in the cloud. In the black-grey market, cloud phones are commonly used for batch account registration, traffic inflation, coupon abuse, mass-controlled order grabbing, and other cheating activities. Black-grey market actors obtain cloud phone access through membership or rental, leveraging remote connections to attack, simultaneously controlling large numbers of cloud phone instances for scaled automated cheating.",references:[{title:"Cloud Phone - Baidu Baike",link:"https://baike.baidu.com/item/%E4%BA%91%E6%89%8B%E6%9C%BA/8154883?fr=aladdin"},{title:"Cloud Phones: The Invisible Threat",link:"https://www.group-ib.com/blog/cloud-phones-invisible-threat/"}]},V={AT0016:K},N=Object.freeze(Object.defineProperty({__proto__:null,AT0016:K,default:V},Symbol.toStringTag,{value:"Module"})),Q={title:"Multi-Instance Tools",description:"Multi-instance software allows running multiple clients of the same software simultaneously on one device, with each client operating normally. It is a tool that removes restrictions on single-instance software programs and games, enabling multiple clients to run without a virtual machine.",references:[{title:"What Is Multi-Instance Software?",link:"https://www.zhihu.com/question/53687531"}]},J={AT0017:Q},Y=Object.freeze(Object.defineProperty({__proto__:null,AT0017:Q,default:J},Symbol.toStringTag,{value:"Module"})),Z={title:"Root/Jailbreak Tools",description:"Root refers to obtaining superuser administrator privileges on Android phones. After gaining root access, the Android superuser account can be used to flash custom ROMs, modify files, or enable originally disabled features. The account has permissions to access and modify almost all files on the phone. Jailbreaking is the equivalent of Root on Apple's iOS system.",references:[{title:"What Are Root Tools?",link:"https://zhidao.baidu.com/question/498839280.html"}]},X={AT0018:Z},$=Object.freeze(Object.defineProperty({__proto__:null,AT0018:Z,default:X},Symbol.toStringTag,{value:"Module"})),ee={title:"Offline Game Bots",description:"Offline game bots are specially designed programs that use a large number of computer hosts (compromised machines or proxy service providers) to simulate normal game clients sending and receiving data packets to game servers. Game servers cannot distinguish the true source of these large numbers of data packets, often causing server load to exceed maximum limits, resulting in login failures, connection timeouts, server crashes, or other serious consequences.",references:[{title:"Offline Game Bots - Baidu Baike",link:"https://baike.baidu.com/item/%E8%84%B1%E6%9C%BA%E6%8C%82/10371991?fr=aladdin"}],avoidances:["A0010","A0010-004","A0001-004","A0013","A0014","A0022"],directCauseRisks:["R0001","R0012","R0108"],indirectSupportRisks:["R0050","R0051","R0051-001"]},te={AT0019:ee},ie=Object.freeze(Object.defineProperty({__proto__:null,AT0019:ee,default:te},Symbol.toStringTag,{value:"Module"})),ae={title:"Hardware ROM Modification Tools",description:"Android is an open-source operating system, allowing developers to customize ROMs. Some developers with malicious intent create ROMs that can arbitrarily modify phone operating system parameters, known as 'hardware modification'. This method is more difficult for developers but makes changes at the OS framework level that apps cannot detect at all. Hardware-modified devices can generate device parameters locally at random or dynamically receive real parameters from other devices via a cloud device library.",references:[{title:"Excerpts from 'Risk Control Essentials'",link:"https://maimai.cn/article/detail?fid=1634043605&efid=NRS3hReqt2jxgj0xruuOGg"}]},oe={AT0020:ae},ne=Object.freeze(Object.defineProperty({__proto__:null,AT0020:ae,default:oe},Symbol.toStringTag,{value:"Module"})),re={title:"Custom Browsers",description:"Custom browsers (also known as fingerprint browsers or anti-detect browsers) are tools that modify browser cores or create independent browser environments to customize browser fingerprint parameters (such as User-Agent, Canvas, WebGL, font lists, etc.), achieving the goal of forging new browser identities. Many professional companies abroad sell such paid browser software, including Antidetect, Multilogin, GoLogin, and AdsPower. They also provide features such as automatic proxy, mass control, cookie robots, and device standard libraries, with visual interfaces for easy operation. Black-grey market actors use custom browsers to simultaneously operate a large number of uncorrelated browser identities on the same computer for batch registration, multi-account operation, traffic inflation, coupon abuse, and other cheating activities.",references:[{title:"Excerpts from 'Risk Control Essentials'",link:"https://maimai.cn/article/detail?fid=1634043605&efid=NRS3hReqt2jxgj0xruuOGg"}],avoidances:["A0001","A0010","A0021","A0021-001","A0029-003","A0059"],directCauseRisks:[],indirectSupportRisks:["R0001-002","R0003-003","R0005-001","R0005-002","R0008","R0016","R0027","R0030-001","R0034","R0050"]},se={AT0021:re},le=Object.freeze(Object.defineProperty({__proto__:null,AT0021:re,default:se},Symbol.toStringTag,{value:"Module"})),ce={title:"Headless Browsers",description:"A headless browser is a browser without a graphical user interface (GUI) but with a complete browser core (including JavaScript parsing engine, rendering engine, etc.). It can be programmatically controlled via scripts to simulate real browser usage scenarios for page access, form submission, screenshots, and other operations. Common headless browser tools include Puppeteer (Chrome), Playwright (multi-browser), and Selenium. In the black-grey market, headless browsers are primarily used for web scraping to capture various types of data on the web, and are also commonly used for batch registration, automated traffic inflation, price monitoring, and other scenarios. Due to their interface-free nature, they run efficiently and are difficult to detect.",references:[{title:"How to Choose a Headless Browser for Web Scraping",link:"https://blog.csdn.net/Z_suger7/article/details/125603480"}],avoidances:["A0001","A0010","A0021","A0021-001","A0029-003","A0059"],directCauseRisks:[],indirectSupportRisks:["R0001-002","R0003-003","R0005-001","R0016","R0027","R0030-001","R0034","R0050"]},de={AT0022:ce},ue=Object.freeze(Object.defineProperty({__proto__:null,AT0022:ce,default:de},Symbol.toStringTag,{value:"Module"})),pe={title:"Automation Scripts",description:"Automation scripts automate repetitive operations that would otherwise require manual execution through code. In many cases, they do not involve exploiting system vulnerabilities but simply automate manual operations through machines, a common means for developers to improve daily work efficiency. In the black-grey market, automation scripts are commonly used for batch registration, automated traffic inflation, grabbing red packets, snapping up coupons, auto-order grabbing, and other scenarios, serving as an important tool for black-grey market actors to achieve scaled cheating.",references:[{title:"The Difference Between Vulnerabilities and Automation Scripts",link:"https://zhuanlan.zhihu.com/p/22456562"}],avoidances:["A0001","A0001-002","A0001-004","A0002","A0004","A0005","A0009","A0010","A0015","A0016","A0021","A0022","A0024","A0029-001","A0059"],directCauseRisks:["R0001","R0001-001","R0002","R0003-001","R0003-002"],indirectSupportRisks:["R0003","R0003-003","R0003-004","R0005","R0005-001","R0009","R0108"]},me={AT0023:pe},ge=Object.freeze(Object.defineProperty({__proto__:null,AT0023:pe,default:me},Symbol.toStringTag,{value:"Module"})),he={title:"GPS Spoofing Tools",description:"GPS spoofing tools (also known as virtual location tools or location disguise tools) are software that modifies device GPS positioning information to disguise the geographic location of a phone or device to any specified location. Using fake location apps, users can disguise their location and simulate GPS coordinates in any country, allowing them to search for any location they want to spoof. In the black-grey market, GPS spoofing tools are commonly used for virtual location check-ins, faking rider locations, remote coupon abuse, false sign-ins, and other scenarios. Additionally, more advanced GPS spoofing methods include using SDR (Software Defined Radio) devices to forge satellite signals, affecting GPS receivers within a target area.",references:[{title:"GPS Spoofing: Everything You Need to Know",link:"https://dmarcreport.com/blog/everything-you-need-to-know-about-gps-spoofing/"}]},fe={AT0024:he},be=Object.freeze(Object.defineProperty({__proto__:null,AT0024:he,default:fe},Symbol.toStringTag,{value:"Module"})),ye={title:"Deobfuscation Tools",description:"Deobfuscation tools are tools used to restore obfuscated code to a readable form. Obfuscation is a common code protection technique used to hide the true intent and functionality of code, increasing the difficulty of reverse engineering. Deobfuscation tools help developers analyze and understand obfuscated code for vulnerability analysis and security auditing. They typically use static analysis techniques to syntactically and semantically analyze code and restore it to a readable form.",references:[{title:"AST Deobfuscation in Practice",link:"https://www.jianshu.com/p/f485140ad83b"},{title:"Prerequisite Knowledge for AST Deobfuscation: Concepts",link:"https://bbs.huaweicloud.com/blogs/230672"},{title:"JS Reverse Engineering: AST Restoration of Geetest Obfuscated JS in Practice",link:"https://astexplorer.net/"}]},ke={AT0025:ye},Ae=Object.freeze(Object.defineProperty({__proto__:null,AT0025:ye,default:ke},Symbol.toStringTag,{value:"Module"})),ve={title:"Score-Running Platforms",description:"Score-running platforms are online platforms that illegally provide payment settlement services for illegal activities (such as gambling, pornography, and fraud) through third-party payment platforms, partner banks, and other service provider interfaces. When gamblers top up funds on overseas gambling websites, this information is published on score-running platforms, and registered members grab orders in a manner similar to ride-hailing. After successfully grabbing an order, the gambling platform displays a corresponding payment QR code, and the gambler transfers funds directly to the platform member via the QR code.",references:[{title:"'Move Your Fingers, Earn 2,000 Yuan a Day': Score-Running Platform 'Tiantianshangshen' Illegal Settlement and Foreign Exchange Details Exposed",link:"https://baijiahao.baidu.com/s?id=1786676096681952847&wfr=spider&for=pc"},{title:"Harm Analysis and Regulatory Recommendations for Money Laundering via Payment Platforms",link:"https://www.163.com/dy/article/HLB99K1805509NOJ.html"}]},we={AT0026:ve},Re=Object.freeze(Object.defineProperty({__proto__:null,AT0026:ve,default:we},Symbol.toStringTag,{value:"Module"})),Te={title:"Card Vending Platforms",description:"Card vending platforms (auto-delivery card platforms) are online platforms that provide automated transaction services for virtual goods. Merchants can input virtual product information (such as game activation codes, accounts, membership keys, phone recharge cards, etc.) into the platform, and the system automatically delivers goods upon payment, enabling 24/7 unmanned transactions. In the black/gray market, these platforms are widely used for selling and distributing illegal accounts, personal information, black card keys, and other prohibited virtual goods, serving as critical infrastructure for the black/gray market resource trading network. Due to their typical features of anonymity, automated transactions, and rapid fund flow, many criminal groups use them for batch selling of illegal virtual goods and fund settlement.",references:[{title:"Behind the Scaling of Gray/Black Markets: The Resource Trading Network Composed of Card Vending Platforms",link:"https://www.163.com/dy/article/ED1Q6CVF0518STKV.html"}]},Se={AT0027:Te},_e=Object.freeze(Object.defineProperty({__proto__:null,AT0027:Te,default:Se},Symbol.toStringTag,{value:"Module"})),Ce={title:"Decompilation Tools",description:"Computer software reverse engineering refers to performing reverse analysis and research on another party's software target program (such as an executable program) to deduce the design elements such as ideas, principles, structure, algorithms, processing procedures, and operating methods used in their software product, and in certain cases possibly deriving the source code. Android reverse engineering is a technique for decompiling packaged APPs and analyzing source code to understand APP implementation logic.",references:[{title:"Decompilation - Baidu Baike",link:"https://baike.baidu.com/item/%E5%8F%8D%E5%90%91%E7%BC%96%E8%AF%91/9932384?fromtitle=%E5%8F%8D%E7%BC%96%E8%AF%91&fromid=8748947&fr=aladdin"},{title:"What Is Android Reverse Engineering?",link:"https://blog.csdn.net/wqwq_22/article/details/122778209"}]},Pe={AT0028:Ce},Me=Object.freeze(Object.defineProperty({__proto__:null,AT0028:Ce,default:Pe},Symbol.toStringTag,{value:"Module"})),je={title:"Image CAPTCHA Recognition Tools",description:"Image CAPTCHA recognition tools are technical tools used to automatically identify and crack various types of graphical CAPTCHAs. Early versions were primarily based on OCR (Optical Character Recognition) technology, which confirms character shapes by examining light and dark patterns in images and converts them into computer text. With the evolution of CAPTCHA technology and the development of deep learning, modern CAPTCHA recognition tools widely use deep learning-based image recognition models (such as CNN, Caffe frameworks, etc.), significantly improving recognition rates for multiple CAPTCHA types including character CAPTCHAs, slider CAPTCHAs, and click-selection CAPTCHAs. In the black/gray market, such tools typically operate as 'CAPTCHA-solving platforms' (打码平台), providing batch automated CAPTCHA recognition services. Criminal groups encapsulate captured CAPTCHA information as tasks and submit them to these platforms, which return results through AI models or human labor, thereby bypassing websites' CAPTCHA security protections.",references:[{title:"Tesseract-OCR Image Text Recognition Tool",link:"https://blog.csdn.net/weixin_43656359/article/details/103401848"},{title:"Black Market Uses 'Future Weapons' to Crack CAPTCHAs — 'Kuai'a Dama' Platform Uses Deep Learning Caffe Framework",link:"https://blog.csdn.net/fuhanghang/article/details/118538724"}],avoidances:["A0001","A0001-002","A0001-004"],directCauseRisks:[],indirectSupportRisks:["R0001-001","R0001-002","R0005-001","R0047"]},Oe={AT0029:je},Ie=Object.freeze(Object.defineProperty({__proto__:null,AT0029:je,default:Oe},Symbol.toStringTag,{value:"Module"})),Be={title:"Cookie Login Tools",description:"By extracting, stealing, or purchasing cookies from already-logged-in accounts, these tools perform credential reuse to achieve 'login-free' authentication for accounts.",references:[{title:"What Are Amazon Cookie Buyer Accounts?",link:"https://www.sohu.com/na/471863234_121085313"}],avoidances:["A0010","A0015","A0019","A0021","A0029-001","A0059"],directCauseRisks:["R0003","R0003-001","R0003-002","R0003-003","R0003-004","R0005","R0005-001","R0032","R0035","R0105"],indirectSupportRisks:["R0016","R0034","R0037"]},xe={AT0030:Be},ze=Object.freeze(Object.defineProperty({__proto__:null,AT0030:Be,default:xe},Symbol.toStringTag,{value:"Module"})),Ee={title:"Crowdsourcing Platforms",description:"Crowdsourcing refers to a model where gangs or organizations recruit large numbers of volunteer workers online to complete tasks in bulk for small rewards. Due to current technological limitations, no intelligent or automated technology can match normal human operation levels. Therefore, crowdsourcing can easily bypass various security protections and identification strategies. Since all resource requesters are real users, even if crowdsourcing behavior can be identified, it is difficult to implement countermeasures without causing significant impact and complaints.",references:[{title:"Revealing the Current State of Micro-Crowdsourcing Industry: Gray/Black Markets Flourish, Opportunities and Challenges Coexist",link:"https://weibo.com/ttarticle/p/show?id=2309404682250288758796"}],avoidances:["A0018","A0033","A0019","A0024","A0029-001","A0059","A0060"],directCauseRisks:[],indirectSupportRisks:["R0003","R0003-002","R0003-003","R0005-002","R0008","R0015","R0016","R0016-001","R0017","R0017-001","R0047","R0056"]},De={AT0031:Ee},Fe=Object.freeze(Object.defineProperty({__proto__:null,AT0031:Ee,default:De},Symbol.toStringTag,{value:"Module"})),He={title:"Browser Extensions",description:"Includes but is not limited to malicious promotional extensions, price comparison extensions, ad-blocking extensions, and membership benefit acquisition extensions.",references:[{title:"Case Report on Unfair Competition by Browser Extensions",link:"https://www.163.com/dy/article/HB8OBS1L051187VR.html"}],avoidances:["A0001","A0010","A0010-004"],directCauseRisks:["R0003-001","R0003-002","R0007","R0007-001","R0007-002","R0007-003","R0007-004","R0008","R0008-001","R0013","R0032"],indirectSupportRisks:["R0001","R0001-002","R0003","R0003-003","R0003-004","R0005","R0005-001","R0009","R0016","R0018","R0024"]},qe={AT0032:He,"AT0032-001":{title:"Hijacking Extensions",description:"Browser extensions that hijack legitimate traffic through unconventional means such as viruses, trojans, unauthorized bundled installs, forced homepage changes, browser or address bar hijacking, page hijacking, search engine manipulation, or user data tampering. They may also hijack traffic by modifying URL parameters or injecting pop-ups during normal user browsing. An example is monitoring IE access via Microsoft's COM connection point technology (the traditional BHO method) to generate or modify affiliate URLs.",references:[{title:"A Well-Known Chinese Browser Extension Caught Hijacking and Monitoring User Pages and Spamming Ads",link:"https://baijiahao.baidu.com/s?id=1707302172260893117&wfr=spider&for=pc"}],avoidances:["A0001","A0010","A0013","A0014"],directCauseRisks:["R0007","R0008-001","R0013","R0067","R0083-001"],indirectSupportRisks:[]}},We=Object.freeze(Object.defineProperty({__proto__:null,AT0032:He,default:qe},Symbol.toStringTag,{value:"Module"})),Le={title:"Surveillance and Eavesdropping Devices",description:"Surveillance and eavesdropping devices are tools used for monitoring and intercepting communications, typically used illegally or without authorization. These devices are designed to obtain people's private information, eavesdrop on conversations, or collect sensitive data, potentially leading to privacy breaches, illegal surveillance, and other security threats.",references:[{title:"Eavesdropping - Baidu Baike",link:"https://baike.baidu.com/item/%E7%AA%83%E5%90%AC/20600680?fr=ge_ala"},{title:"Public Security Organs Crack Down on Illegal Eavesdropping and Surveillance Devices",link:"https://www.mps.gov.cn/n2255079/n8310277/n8568134/n8568146/c8627029/content.html"}],avoidances:["A0017-001","A0041","A0051","A0062","A0044"],directCauseRisks:["R0059","R0112","R0112-002","R0112-005"],indirectSupportRisks:[]},Ge={AT0033:Le},Ue=Object.freeze(Object.defineProperty({__proto__:null,AT0033:Le,default:Ge},Symbol.toStringTag,{value:"Module"})),Ke={title:"Risk IP Addresses",description:"Risk IP addresses are IP addresses considered unsafe in the network security domain. They may be malicious IPs, IPs being maliciously exploited, or IPs that have been misjudged. Risk IP addresses are classified into three risk levels: high, medium, and low. High-risk IPs are considered malicious, medium-risk IPs are being maliciously exploited, and low-risk IPs are misjudged.",references:[{title:"Introduction to IP Risk Profiling Technology",link:"https://www.163.com/dy/article/HT4OLRVB0553MFFW.html"}],avoidances:["A0018","A0016-001","A0029-002"],directCauseRisks:[],indirectSupportRisks:["R0001-002","R0003","R0003-001","R0003-002","R0003-003","R0003-004","R0005","R0005-001","R0009","R0016","R0017-001","R0027","R0030-001","R0032-001","R0032-002","R0032-003","R0037","R0040","R0049"]},Ve={AT0034:Ke,"AT0034-001":{title:"Proxy IP",description:"A proxy IP is a network proxy technique used to conceal a device's real IP address. The client first connects to the proxy IP, which then forwards the request to the target website, leaving only the proxy IP in the site's access logs. Common proxy IP types include HTTP proxies, HTTPS proxies, and SOCKS proxies.",references:[{title:"What Is a Proxy IP?",link:"http://web-auto.91ajs.com/information/type-of-proxy-ip.html"}],avoidances:["A0016-001","A0029-002","A0038","A0038-002"],directCauseRisks:["R0001-002","R0003","R0003-001","R0003-002","R0003-003","R0003-004","R0005","R0005-001","R0009","R0016","R0017-001","R0027","R0030-001","R0032-001","R0032-002","R0032-003","R0037","R0040","R0049"],indirectSupportRisks:[]},"AT0034-002":{title:"Second-Dial IP",description:"A 'second-dial IP' exploits the fact that home broadband connections obtain a new IP address each time they reconnect. Criminals rent large numbers of home broadband lines and rapidly generate millions of IP addresses to form an 'IP pool', which is then provided to cybercrime groups. The resulting massive volume of IP addresses circumvents normal IP-based restrictions, making it extremely difficult for law enforcement to trace criminal activity.",references:[{title:"People's Daily Commentary: The 'Second-Dial IP' Black Market Must Be Struck Down Immediately",link:"https://baijiahao.baidu.com/s?id=1722257035210193072&wfr=spider&for=pc"}],avoidances:["A0016-001","A0029-002","A0038","A0038-002"],directCauseRisks:["R0001-002","R0003","R0003-001","R0003-002","R0003-003","R0005","R0005-001","R0009","R0016","R0017-001","R0027","R0030-001","R0032-001","R0032-002","R0032-003","R0037","R0040","R0049"],indirectSupportRisks:[]}},Ne=Object.freeze(Object.defineProperty({__proto__:null,AT0034:Ke,default:Ve},Symbol.toStringTag,{value:"Module"})),Qe={title:"Packet Sending/Modification Tools",description:"Packet sending and modification tools are network debugging tools primarily used to capture, analyze, and edit network data packets. Through these tools, users can monitor network traffic, analyze protocols, and debug network issues. For example, Burp Suite is a web application security testing tool that can capture, analyze, and modify HTTP/HTTPS packets. These tools are widely used in network security, system debugging, and network performance analysis.",references:[{title:"Packet Modification Tools - Penetration Testing Tool Burp Suite Explained",link:"https://zhuanlan.zhihu.com/p/537832119"}],avoidances:["A0001","A0002","A0004","A0010","A0015","A0022","A0025","A0025-002","A0031","A0032"],directCauseRisks:["R0001","R0001-001","R0002","R0003-001","R0003-002","R0008-001","R0027","R0032-001","R0032-002","R0032-003","R0034","R0051-002"],indirectSupportRisks:["R0003","R0003-003","R0003-004","R0005","R0005-001"]},Je={AT0035:Qe},Ye=Object.freeze(Object.defineProperty({__proto__:null,AT0035:Qe,default:Je},Symbol.toStringTag,{value:"Module"})),Ze={title:"Device Wipe Tools",description:"Device wipe tools completely reset a device to factory settings, clearing all user data, modifying device fingerprint data, and clearing all locally stored data from installed apps. After wiping, the device is theoretically a brand new device.",references:[{title:"Android One-Click New Device Software - Root-Free Device Fingerprint Reset",link:"https://zhuanlan.zhihu.com/p/534705816"}]},Xe={AT0036:Ze},$e=Object.freeze(Object.defineProperty({__proto__:null,AT0036:Ze,default:Xe},Symbol.toStringTag,{value:"Module"})),et={title:"Phone Backup and Restore Tools",description:"These tools perform comprehensive backups of a phone's current state, data, and device fingerprints, and restore them when needed. They can back up all files generated by a target app during runtime, then restore those files on a new device to deceive the app's server into thinking the account has always been operated on the same device, gradually increasing account permissions for account nurturing and user retention purposes.",references:[{title:"Device Fingerprint Spoofing: A Comprehensive Analysis",link:"https://www.incognia.com/blog/device-fingerprint-spoofing"}]},tt={AT0037:et},it=Object.freeze(Object.defineProperty({__proto__:null,AT0037:et,default:tt},Symbol.toStringTag,{value:"Module"})),at={title:"Account Rental Platforms",description:"Account rental platforms are online trading platforms that provide account rental services. Users can select rental accounts for desired games and server regions, make secure payments, and then experience the game. Account rental platforms allow players to enjoy better gaming experiences at minimal cost.",references:[{title:"Court Rules: Platform Providing Game Account Rental Services Constitutes Unfair Competition",link:"https://baijiahao.baidu.com/s?id=1761867759016584999&wfr=spider&for=pc"}]},ot={AT0038:at},nt=Object.freeze(Object.defineProperty({__proto__:null,AT0038:at,default:ot},Symbol.toStringTag,{value:"Module"})),rt={title:"Identity Document Set (4-Piece)",description:"The 4-piece identity document set refers to an ID card, the corresponding phone SIM card, the corresponding bank card, and an online banking USB key. This complete identity impersonation package is known as the '4-piece set' in black markets. Generally, the bank cards already have online banking activated, and some SIM cards even have prepaid credit. More sophisticated 4-piece set dealers can even customize specific hometown, gender, age, mobile carrier, and bank for buyers.",references:[{title:"3,200 People Used '4-Piece Sets' and '8-Piece Sets' to Commit Crimes",link:"https://www.thepaper.cn/newsDetail_forward_10024890"}]},st={AT0039:rt,"AT0039-001":{title:"Money Laundering Bank Cards",description:"Bank cards used by criminal networks to launder illicit funds (i.e., to legitimize proceeds of crime). For example, gambling and fraud rings use these cards to transfer and launder money via purchases and bank transfers.",references:[{title:"What Does Bank Card Money Laundering Mean? Sentencing Standards for the Crime of Money Laundering",link:"https://www.ruilaw.cn/zhishi/1681775034355291.html"}]},"AT0039-002":{title:"Money Laundering Digital Wallets",description:"Encrypted digital currency accounts or digital wallets used by criminal networks to launder illicit funds. For example, criminals transfer funds via digital currency payments and transfers, exploiting the anonymity of digital currencies to evade regulatory scrutiny.",references:[{title:"Zhejiang Shaoxing Yuecheng Police Crack Money Laundering Case Using Digital Yuan Accounts",link:"https://m.gmw.cn/2024-01/23/content_1303639818.htm"}]}},lt=Object.freeze(Object.defineProperty({__proto__:null,AT0039:rt,default:st},Symbol.toStringTag,{value:"Module"})),ct={title:"Corporate Identity Document Set (8-Piece)",description:"The 8-piece corporate identity document set refers to 8 items: corporate bank card, USB key, legal representative ID card, business license, corporate account, company seal, legal representative personal seal, and corporate account opening permit. These are essential tools for implementing telecom network fraud and money laundering. The key step in telecom fraud is transferring stolen funds, and criminals purchase these personal or corporate accounts through various illegal channels at high prices to achieve their illegal purposes.",references:[{title:"3,200 People Used '4-Piece Sets' and '8-Piece Sets' to Commit Crimes",link:"https://www.thepaper.cn/newsDetail_forward_10024890"}],avoidances:["A0017","A0015","A0023-001","A0044"],directCauseRisks:[],indirectSupportRisks:["R0010","R0043","R0044","R0049","R0060","R0062"]},dt={AT0040:ct,"AT0040-001":{title:"Money Laundering Corporate Bank Accounts",description:"Corporate bank accounts used by criminal networks to launder illicit funds. Because corporate accounts support high transaction limits and frequent transfers, they are commonly used as both collection hubs and distribution points for laundering illicit money.",references:[{title:"3,200 People Exploiting '4-Piece' and '8-Piece' Sets — Chenzhou Police Dismantle Large-Scale SIM/Bank Card Black Market",link:"https://www.thepaper.cn/newsDetail_forward_10024890"}],avoidances:["A0016","A0015","A0044"],directCauseRisks:["R0044","R0060","R0062","R0093"],indirectSupportRisks:[]}},ut=Object.freeze(Object.defineProperty({__proto__:null,AT0040:ct,default:dt},Symbol.toStringTag,{value:"Module"})),pt={title:"Offer Wall Tools",description:"An Offer Wall Tool is an advertising or marketing tool typically used with mobile apps or online platforms. Its main purpose is to earn virtual points, reward points, or coupons by having users complete specific tasks, activities, or transactions. These tasks typically include participating in surveys, trying other apps, registering memberships, and watching ad videos. Offer wall tools are usually provided by advertising platforms or third-party providers and integrated into apps or websites to increase user engagement and retention.",references:[{title:"Offer Wall - Baidu Baike",link:"https://baike.baidu.com/item/%E7%A7%AF%E5%88%86%E5%A2%99/7058877?fr=ge_ala"},{title:"2021 Mobile Advertising Anti-Fraud White Paper",link:"https://cloud.tencent.com/developer/article/1970514"}]},mt={AT0041:pt},gt=Object.freeze(Object.defineProperty({__proto__:null,AT0041:pt,default:mt},Symbol.toStringTag,{value:"Module"})),ht={title:"Credential Stuffing Tools",description:"Credential stuffing tools use leaked username and password data (typically from data breaches on one website) to automate batch login attempts on other websites or systems. The core principle of credential stuffing is that many users reuse the same username and password across different websites. Attackers only need to obtain a batch of leaked credentials to attempt bulk logins on numerous target websites within a short time. Credential stuffing differs from brute force attacks: brute force tries all possible password combinations, while credential stuffing directly uses real leaked credentials for matching, making it far more efficient. These tools typically feature batch import of leaked credentials, multi-threaded concurrent login attempts, automatic CAPTCHA recognition (paired with CAPTCHA-solving platforms), proxy IP rotation to evade rate limits and IP bans, and automatic extraction of account information after successful logins.",references:[{title:"Credential Stuffing - Baidu Baike",link:"https://baike.baidu.com/item/%E6%92%9E%E5%BA%93/16480882?fromModule=search-result_lemma-recommend"},{title:"Credential Stuffing - OWASP",link:"https://owasp.org/www-community/attacks/Credential_stuffing"}],avoidances:["A0001","A0001-004","A0004","A0005","A0007","A0009","A0010","A0011","A0012","A0015","A0016","A0021","A0022","A0023","A0029","A0034-003","A0038","A0044","A0059"],directCauseRisks:["R0032-001","R0032-002","R0032-003","R0032-004","R0083-001"],indirectSupportRisks:[]},ft={AT0042:ht},bt=Object.freeze(Object.defineProperty({__proto__:null,AT0042:ht,default:ft},Symbol.toStringTag,{value:"Module"})),yt={title:"Anonymous Communication Tools",description:"Anonymous instant messaging tools are communication applications designed to hide user identity information to provide higher levels of privacy protection, commonly used by criminal groups for covert communication and illegal activity coordination. Common tools include: Telegram — an instant messaging app providing end-to-end encrypted secret chats, self-destructing messages, anonymous usernames, channels, and groups. Due to its strong encryption and difficulty of legal jurisdiction, it has become a widely used communication tool in the black/gray market for data trading, illegal information dissemination, and criminal coordination. Signal — a privacy-focused instant messaging app with end-to-end encrypted message transmission ensuring only communicating parties can read messages. Signal requires a phone number for registration but supports setting usernames to hide the phone number. Features such as end-to-end encryption, self-destructing messages, and anonymity make these tools useful for privacy protection while also being exploited by criminal groups to evade regulation and law enforcement tracking.",references:[{title:"Telegram - Baidu Baike",link:"https://baike.baidu.com/item/Telegram/6974663?fr=ge_ala"},{title:"Telegram Becomes a 'Hotbed' for Black/Gray Markets",link:"https://news.qq.com/rain/a/20240826A05D1U00"}]},kt={AT0043:yt},At=Object.freeze(Object.defineProperty({__proto__:null,AT0043:yt,default:kt},Symbol.toStringTag,{value:"Module"})),vt={title:"Click Simulation Tools",description:"Click simulation tools are software or applications designed to simulate user click or touch operations to automatically execute tasks related to graphical user interface (GUI) interaction. These tools are typically used to automate and simplify repetitive tasks, especially in software testing, screen recording, automation script writing, and data collection. Features include mouse simulation, touch simulation, keyboard simulation, screen coordinate control, recording and playback, and multi-platform support.",references:[{title:"Click Simulator Software Collection",link:"https://www.youxiniao.com/zt/mndjq85/"}]},wt={AT0044:vt},Rt=Object.freeze(Object.defineProperty({__proto__:null,AT0044:vt,default:wt},Symbol.toStringTag,{value:"Module"})),Tt={title:"Flash Sale Tools",description:"Flash sale tools are software that assists users in grabbing items on shopping platforms by automatically identifying and simulating manual operations to achieve fast order placement. These tools are typically used to grab hot-selling or discounted items, helping users improve their chances of success. Features include automatic product information recognition, automatic order form filling, automatic order submission, and automatic page refresh.",references:[{title:"Recommended Taobao Flash Sale Tools",link:"https://jianghu.taobao.com/detail/47301_37852915"}]},St={AT0045:Tt},_t=Object.freeze(Object.defineProperty({__proto__:null,AT0045:Tt,default:St},Symbol.toStringTag,{value:"Module"})),Ct={title:"Ranking Manipulation Tools",description:"Ranking manipulation tools simulate manual operations to inflate network clicks, views, comments, and other metrics. These tools generally fall into two categories: human-powered and machine-powered. Human-powered means real users download specified apps — this method has the lowest risk and best results but higher cost. Machine-powered tools either simulate user search, download, and install data from different regions without needing real phones, or establish studios with large numbers of phones running automated scripts and one-click device spoofing programs.",references:[{title:"SEO Software: Ranking Booster!",link:"https://baijiahao.baidu.com/s?id=1768567058264202835&wfr=spider&for=pc"}]},Pt={AT0046:Ct},Mt=Object.freeze(Object.defineProperty({__proto__:null,AT0046:Ct,default:Pt},Symbol.toStringTag,{value:"Module"})),jt={title:"Task Completion Tools",description:"Task completion tools are automated or semi-automated tools used to execute repetitive or tedious tasks to improve work efficiency and quality. These tools can automatically or semi-automatically complete various tasks such as data entry, information scraping, web crawling, and process automation according to user needs and custom settings.",references:[{title:"Game Automation Script Tools and Black Market Activity Analysis",link:"https://dy.163.com/article/J56P34K40541BQVC.html"}]},Ot={AT0047:jt},It=Object.freeze(Object.defineProperty({__proto__:null,AT0047:jt,default:Ot},Symbol.toStringTag,{value:"Module"})),Bt={title:"Virtual Machine",description:"A Virtual Machine (VM) is a software entity that simulates an actual computer system on computer hardware. Through software-level virtualization technology, it divides a physical computer into multiple independent and mutually isolated virtual environments, each called a virtual machine.",references:[{title:"Virtual Machine - Baidu Baike",link:"https://baike.baidu.com/item/%E8%99%9A%E6%8B%9F%E6%9C%BA?fromModule=lemma_search-box"}]},xt={AT0048:Bt},zt=Object.freeze(Object.defineProperty({__proto__:null,AT0048:Bt,default:xt},Symbol.toStringTag,{value:"Module"})),Et={title:"Game Cheats",description:"Game cheats refer to modifying or manipulating games through illegal means or third-party software to gain unfair game advantages or engage in other violations. Cheats may include cheat software that modifies game memory, files, or data to achieve functions not allowed by game design such as invincibility, auto-aim, and wallhacks; automation scripts that simulate player behavior to automatically perform operations like auto-grinding and auto-leveling; external modification tools; virtual currency and equipment trading; and cheat codes and vulnerability exploitation.",references:[{title:"Game Cheats - Baidu Baike",link:"https://baike.baidu.com/item/%E5%A4%96%E6%8C%82?fromtitle=%E6%B8%B8%E6%88%8F%E5%A4%96%E6%8C%82&fromid=2748874&fromModule=lemma_search-box"},{title:"A Systematic Review of Technical Defenses Against Software-Based Cheating in Online Multiplayer Games",link:"https://arxiv.org/html/2512.21377v1"}],avoidances:["A0010","A0010-004","A0015","A0059","A0020"],directCauseRisks:["R0001-002","R0012","R0012-002","R0100","R0102","R0103","R0104","R0108"],indirectSupportRisks:[]},Dt={AT0049:Et},Ft=Object.freeze(Object.defineProperty({__proto__:null,AT0049:Et,default:Dt},Symbol.toStringTag,{value:"Module"})),Ht={title:"Auto-Posting Bots",description:"An auto-posting bot is an automated tool that can bulk-post messages, comments, or replies on forums, social media platforms, and blogs for purposes such as spam flooding, traffic diversion, promotion, or public opinion manipulation. These bots typically feature multi-account management, content template variable substitution, scheduled posting, auto-bumping, CAPTCHA recognition, and the ability to simulate real user behavior to bypass basic platform defenses. In gray/black market scenarios, auto-posting bots are widely used for spam campaigns, astroturfing, SEO backlink building, and fake content dissemination.",references:[{title:"How Are Auto-Scripting Tools Like Key Wizard Punished",link:"https://dy.163.com/article/J56P34K40541BQVC.html"}],avoidances:["A0001","A0001-004","A0004","A0005","A0006","A0010","A0015","A0018","A0020","A0021","A0022","A0023","A0024","A0029","A0038","A0059"],directCauseRisks:["R0001-002","R0015","R0021","R0024","R0056","R0110"],indirectSupportRisks:[]},qt={AT0050:Ht},Wt=Object.freeze(Object.defineProperty({__proto__:null,AT0050:Ht,default:qt},Symbol.toStringTag,{value:"Module"})),Lt={title:"Risk Email Accounts",description:"From a defense perspective against gray/black markets, risk email accounts are email accounts that may be exploited by criminal actors. They mainly fall into two categories: first, large numbers of legitimate email accounts obtained through malicious registration, fraud, and cyberattacks, used for illegal activities such as sending spam, online fraud, and data breaches; second, temporary email accounts (disposable emails) that can be quickly obtained without real-name registration and are heavily used by criminal actors for batch registration of fake accounts and bypassing email verification.",references:[{title:"Black Market Big Data: Malicious Email Accounts See New Surge",link:"https://m.thepaper.cn/baijiahao_14534771"}]},Gt={AT0051:Lt},Ut=Object.freeze(Object.defineProperty({__proto__:null,AT0051:Lt,default:Gt},Symbol.toStringTag,{value:"Module"})),Kt={title:"Malicious Peripherals",description:"Malicious peripherals are devices into which malicious software writes malicious code via USB interfaces or other means. When the peripheral is plugged into a computer, the malicious code automatically runs, thereby attacking the computer.",references:[{title:"Hardware Additions - MITRE ATT&CK T1200",link:"https://attack.mitre.org/techniques/T1200/"}],avoidances:["A0062","A0041"],directCauseRisks:["R0080","R0112","R0112-003","R0112-004","R0112-005"],indirectSupportRisks:[]},Vt={AT0052:Kt,"AT0052-001":{title:"KON-Boot",description:"KON-Boot is a tool that bypasses Windows and macOS login passwords. It boots from a USB device to circumvent the login authentication process.",references:[{title:"KON-Boot Bypassing Windows Authentication - CSDN",link:"https://blog.csdn.net/weixin_52497013/article/details/121848172"}],avoidances:["A0062","A0041"],directCauseRisks:["R0067","R0083-001","R0112","R0112-003"],indirectSupportRisks:[]},"AT0052-002":{title:"USB Killer",description:"USB Killer is a device that injects high-voltage electrical current into a computer via the USB port, instantly burning out hardware components such as the motherboard, CPU, and RAM.",references:[{title:"How USB Killer Damages Computers - Zhihu",link:"https://zhuanlan.zhihu.com/p/153254485"}],avoidances:["A0062","A0041"],directCauseRisks:["R0082","R0112","R0112-003","R0112-004"],indirectSupportRisks:[]},"AT0052-003":{title:"BadUSB",description:"BadUSB is a USB device pre-loaded with malicious code. When inserted into a computer, the malicious code executes automatically, enabling attacks such as keystroke injection, data exfiltration, or malware installation.",references:[{title:"BadUSB Detailed Tutorial - Jianshu",link:"https://www.jianshu.com/p/76b42b276bee"}],avoidances:["A0062","A0041"],directCauseRisks:["R0067","R0080","R0083-001","R0112","R0112-003","R0112-005"],indirectSupportRisks:[]}},Nt=Object.freeze(Object.defineProperty({__proto__:null,AT0052:Kt,default:Vt},Symbol.toStringTag,{value:"Module"})),Qt={title:"Malicious AI Applications",description:"The term 'malicious AI applications' describes practices that use artificial intelligence technology for malicious purposes or illegal activities. These technologies may be abused in violation of laws and ethical standards, causing potential harm. Related concepts include Deepfake technology for generating realistic fake content, fusion of malware with AI to evade detection, social engineering using natural language processing, AI-powered cyberattacks, automated large-scale network attacks, and AI-generated online fraud content.",references:[{title:"Beware of AI Black Industry Chain Batch-Generating Defamatory Content",link:"https://baijiahao.baidu.com/s?id=1771272671713776437&wfr=spider&for=pc"}],avoidances:["A0006-008"],directCauseRisks:["R0006","R0012-002","R0015","R0021","R0023","R0056","R0071","R0084","R0110"],indirectSupportRisks:["R0047","R0048"]},Jt={AT0053:Qt,"AT0053-001":{title:"AI Fraud Chatbots",description:"AI fraud chatbots are chatbots built with artificial intelligence and natural language processing capabilities, designed to conduct deceptive and fraudulent activities. They simulate realistic conversations to trick users into revealing personal or financial information, or into taking harmful actions. Typical fraud scenarios include social engineering (gaining trust to extract sensitive credentials), fake investment advice (promoting fraudulent opportunities to steal funds), romance scams (simulating relationships to solicit money), fake customer service (impersonating legitimate companies to harvest credentials), and malicious link distribution (embedding phishing links within conversations).",references:[{title:"AI Application Security Back in the Headlines: AI Chatbots Become a New Tool for Fraud",link:"https://baijiahao.baidu.com/s?id=1765497083313841378&wfr=spider&for=pc"},{title:"'AI' Voice Bots Turned Into Fraud Weapons? Telecom Scam Tactics Are Evolving — Stay Alert!",link:"https://baijiahao.baidu.com/s?id=1787666481258718079&wfr=spider&for=pc"}],avoidances:["A0006","A0006-008"],directCauseRisks:["R0024","R0053","R0066","R0095"],indirectSupportRisks:[]},"AT0053-002":{title:"AI Deepfake Video",description:"Criminal networks use AI face-swapping tools at scale to produce deepfake videos for identity verification bypass services. For example, when a social media account triggers a platform's risk control and requires facial authentication, criminals use AI face-swapping to pass the check. Additionally, cases of fraud via conferencing software combined with real-time AI face-swapping are increasingly common — scammers instruct victims to install a video conferencing app, then impersonate a trusted acquaintance through real-time face-swapping to gain the victim's trust and steal funds.",references:[{title:"AI Deepfake Videos — Can You Tell the Difference?",link:"https://baijiahao.baidu.com/s?id=1644436446016986485&wfr=spider&for=pc"},{title:"Video 'Face-Swapping' with 80% Similarity! How to Guard Against AI Deepfake Fraud?",link:"https://baijiahao.baidu.com/s?id=1781674923891589881&wfr=spider&for=pc"}],avoidances:["A0010","A0006-008"],directCauseRisks:["R0048","R0095"],indirectSupportRisks:[]}},Yt=Object.freeze(Object.defineProperty({__proto__:null,AT0053:Qt,default:Jt},Symbol.toStringTag,{value:"Module"})),Zt={title:"System/Application Vulnerability Exploitation Tools",description:"Vulnerability exploitation tools are software or hardware tools used to discover and exploit security vulnerabilities in computer systems or network systems. These tools can be used for vulnerability scanning, vulnerability mining, and vulnerability attacks to assess system security or conduct penetration testing.",references:[{title:"Vulnerability - Baidu Baike",link:"https://baike.baidu.com/item/%E6%BC%8F%E6%B4%9E/1688129?fromModule=disambiguation"},{title:"MITRE ATT&CK - Software",link:"https://attack.mitre.org/software/"}],avoidances:["A0055","A0056"],directCauseRisks:["R0028","R0085","R0086","R0087","R0109"],indirectSupportRisks:[]},Xt={AT0054:Zt},$t=Object.freeze(Object.defineProperty({__proto__:null,AT0054:Zt,default:Xt},Symbol.toStringTag,{value:"Module"})),ei={title:"Covert Recording Devices",description:"Covert recording devices are equipment or tools used for illegal or unauthorized recording of photos, videos, or audio. These tools are typically designed to be very discreet, intended to record without attracting the attention of the monitored subject. Such tools may include cameras, audio recorders, hidden camera devices, or other eavesdropping equipment, and may be misused to violate personal privacy, illegally obtain confidential information, or serve other illegal purposes.",references:[{title:"Covert Recording Devices - Baidu Baike",link:"https://baike.baidu.com/item/%E5%81%B7%E6%8B%8D%E7%A5%9E%E5%99%A8/15594040?fr=ge_ala"}],avoidances:["A0017-001","A0041","A0051","A0052","A0062"],directCauseRisks:["R0059","R0112-003","R0112-005"],indirectSupportRisks:[]},ti={AT0055:ei},ii=Object.freeze(Object.defineProperty({__proto__:null,AT0055:ei,default:ti},Symbol.toStringTag,{value:"Module"})),ai={title:"AI Deepfake Tools",description:"AI deepfake tools are a collection of tools that use deep learning technology (particularly Generative Adversarial Networks and diffusion models) to generate highly realistic fake face images, videos, and audio. These tools can implement face swapping, face reenactment, expression transfer, and full-body synthesis. Representative tools include DeepFaceLab, FaceSwap, Wav2Lip, and various commercial AI face-swapping applications. Attackers use these tools to forge identities for fraud, bypass facial recognition authentication, create fake videos for extortion or opinion manipulation.",references:[{title:"DeepFaceLab - GitHub",link:"https://github.com/iperov/DeepFaceLab"},{title:"AI Security Governance Research Report (2025) - CAICT",link:"https://www.caict.ac.cn/kxyj/qwfb/bps/202601/P020260109784447548497.pdf"}]},oi={AT0056:ai},ni=Object.freeze(Object.defineProperty({__proto__:null,AT0056:ai,default:oi},Symbol.toStringTag,{value:"Module"})),ri={title:"LLM Automated Attack Tools",description:"LLM automated attack tools use the capabilities of large language models (such as GPT, Claude, etc.) to automate and enhance traditional cyberattacks. These tools can automatically generate phishing emails and social engineering scripts, write malicious code and exploit scripts, automate vulnerability scanning and penetration testing, batch generate fake content and reviews, and automate CAPTCHA recognition and bypass. Attackers use prompt engineering, fine-tuning, and agent orchestration techniques to transform general large models into specialized attack assistance tools. They also include tools targeting LLM services themselves, such as prompt injection frameworks, jailbreak toolkits, AI-agent attack orchestration tools, and MCP tool-call abuse tools.",references:[{title:"OWASP Top 10 for LLM Applications",link:"https://owasp.org/www-project-top-10-for-large-language-model-applications/"},{title:"Global Cybersecurity Outlook 2025 - WEF",link:"https://reports.weforum.org/docs/WEF_Global_Cybersecurity_Outlook_2025.pdf"}],avoidances:["A0065","A0087","A0079","A0067","A0001","A0004","A0015","A0064"],directCauseRisks:["R0084","R0117","R0117-001","R0117-002","R0118","R0148"],indirectSupportRisks:[]},si={AT0057:ri},li=Object.freeze(Object.defineProperty({__proto__:null,AT0057:ri,default:si},Symbol.toStringTag,{value:"Module"})),ci={title:"Digital Human Generation Tools",description:"Digital human generation tools use AI technology to create virtual digital human avatars and drive them for real-time interaction. These tools can generate highly realistic virtual character images based on a small amount of real person photos or video material, and achieve real-time lip sync, facial expression changes, and body movements through text-driven or voice-driven methods. In live streaming scenarios, digital humans can conduct 24-hour uninterrupted live-stream e-commerce and interactive chat. Attackers use digital human tools for fake live-stream e-commerce fraud, impersonating real people for social fraud, and batch generating fake account content.",references:[{title:"AI Digital Human Technology Development Report",link:"https://www.iresearch.com.cn/"},{title:"Virtual Digital Human In-depth Industry Report",link:"https://www.qianzhan.com/"}]},di={AT0058:ci},ui=Object.freeze(Object.defineProperty({__proto__:null,AT0058:ci,default:di},Symbol.toStringTag,{value:"Module"})),pi={title:"AI Voice Cloning Tools",description:"AI voice cloning tools use deep learning technology to generate synthetic voices highly similar to a target person based on a small amount of voice samples (typically only a few seconds to a few minutes). These tools use Text-to-Speech (TTS) and Voice Conversion technology to generate cloned voices of any content in real time or offline. Representative technologies include VALL-E, Bark, and Tortoise-TTS. Attackers use voice cloning tools for phone fraud (impersonating friends or leaders), bypassing voiceprint authentication systems, and creating fake audio evidence.",references:[{title:"VALL-E: Neural Codec Language Models",link:"https://arxiv.org/abs/2301.02111"},{title:"AI Voice Cloning Security Risk Analysis",link:"https://www.europol.europa.eu/publications-events/publications/chatgpt-impact-of-large-language-models-law-enforcement"}]},mi={AT0059:pi},gi=Object.freeze(Object.defineProperty({__proto__:null,AT0059:pi,default:mi},Symbol.toStringTag,{value:"Module"})),hi={title:"Cryptocurrency Mixers",description:"A cryptocurrency mixer (also known as a tumbler) is a tool or service that obscures fund flows by mixing cryptocurrency transactions from multiple users. The mixer pools multiple users' cryptocurrencies, processes them through multiple splits, delays, and randomization, then sends equivalent amounts (minus fees) to user-specified new addresses, severing the link between original transactions and final receiving addresses. Common mixing techniques include CoinJoin protocol, zero-knowledge proof mixing (such as Tornado Cash), and cross-chain bridge mixing. Attackers use mixers for money laundering, ransomware payment transfers, dark web transaction fund laundering, and evading financial regulation.",references:[{title:"Tornado Cash Sanctions Event - OFAC",link:"https://home.treasury.gov/news/press-releases/jy0916"},{title:"Cryptocurrency Mixing Technology Analysis",link:"https://www.chainalysis.com/blog/cryptocurrency-mixers/"}]},fi={AT0060:hi},bi=Object.freeze(Object.defineProperty({__proto__:null,AT0060:hi,default:fi},Symbol.toStringTag,{value:"Module"})),yi={title:"API Automated Abuse Tools",description:"API automated abuse tools are a collection of tools specifically targeting Web API interfaces for automated attacks and abuse. These tools can automatically discover and enumerate API endpoints, bypass API rate limits and authentication mechanisms, and batch-call API interfaces for data scraping or business logic abuse. Main functions include API endpoint discovery and enumeration, authentication bypass (token forgery, JWT attacks, OAuth abuse), rate limit bypass (IP rotation, distributed requests, parameter mutation), and business logic abuse (bulk registration, bulk ordering, price tampering).",references:[{title:"OWASP API Security Top 10 2023",link:"https://owasp.org/API-Security/editions/2023/en/0x11-t10/"},{title:"API Security Attack and Defense Practice",link:"https://portswigger.net/web-security/api-testing"}]},ki={AT0061:yi},Ai=Object.freeze(Object.defineProperty({__proto__:null,AT0061:yi,default:ki},Symbol.toStringTag,{value:"Module"})),vi={title:"SIM Swap Toolkit",description:"A SIM swap toolkit is a collection of tools and resources used to carry out SIM swap attacks. A SIM swap attack involves an attacker using social engineering to deceive telecom carrier customer service staff into transferring a target user's phone number to a SIM card controlled by the attacker, thereby taking over the target's phone number and intercepting SMS verification codes to bypass SMS-based two-factor authentication. The toolkit typically includes forged identity document templates, carrier customer service scripts, automated tools for calling carrier customer service, tools for batch verifying phone number status, and accompanying social engineering information collection tools.",references:[{title:"SIM Swap Fraud - FBI IC3",link:"https://www.ic3.gov/PSA/2022/PSA220208"},{title:"SIM Card Swap Attack Prevention Guide - CISA",link:"https://www.cisa.gov/news-events/cybersecurity-advisories"}]},wi={AT0062:vi},Ri=Object.freeze(Object.defineProperty({__proto__:null,AT0062:vi,default:wi},Symbol.toStringTag,{value:"Module"})),Ti={title:"Phishing Kits",description:"A phishing kit is a complete set of tools for quickly deploying phishing attacks, lowering the technical barrier for phishing. Kits typically include: page template libraries with pre-built high-fidelity login page templates for major banks, e-commerce platforms, and social media; credential collection backends for receiving and managing victim-submitted credentials; domain management tools for automated registration and configuration of lookalike domains and SSL certificates; email/SMS bulk sending modules; anti-detection mechanisms including anti-crawling, geo-restrictions, and User-Agent filtering; AiTM (Adversary-in-the-Middle) real-time relay functionality in advanced kits that uses reverse proxy technology to relay victim input to the real website in real-time, intercepting credentials and dynamic verification codes during the login process to bypass multi-factor authentication (MFA); and PhaaS (Phishing-as-a-Service) subscription-based models with technical support, automated updates, and attack analytics, forming a complete underground business model. Representative tools include Gophish (open source) and various commercial phishing kits circulating in underground markets.",references:[{title:"Phishing Kit Analysis - APWG",link:"https://apwg.org/trendsreports/"},{title:"Phishing Attack Toolkit Technical Analysis",link:"https://www.cert.org.cn/"}]},Si={AT0063:Ti},_i=Object.freeze(Object.defineProperty({__proto__:null,AT0063:Ti,default:Si},Symbol.toStringTag,{value:"Module"})),Ci={title:"Infostealers",description:"Infostealers are a class of malware specifically designed to steal sensitive information from victim devices, primarily targeting browser-saved passwords, cookies, autofill data, and cryptocurrency wallet keys. Representative families include RedLine, Raccoon, Vidar, LummaC2 (Lumma), StealC, and Meta. In 2025-2026, infostealers have become the top threat for global data breaches, with single incidents leading to billions of credentials being leaked. Main functions include: (1) Browser data theft: extracting saved login credentials, cookies, credit card information, and autofill data from Chrome, Firefox, Edge, and other browsers. (2) Cryptocurrency wallet theft: searching for and stealing key files and mnemonic phrases from MetaMask, Exodus, and other wallets. (3) Session token theft: stealing session tokens from Discord, Telegram, Steam, and other applications for password-free login. (4) Screenshots and keylogging: periodically capturing screen content and recording keyboard input to harvest unsaved credentials. (5) System information collection: gathering OS version, hardware information, and installed software lists. (6) Data exfiltration: sending stolen data through encrypted channels to attacker-controlled servers or Telegram bots. Infostealers typically spread through phishing emails, fake software downloads, cracked software, and fake VPN applications, with stolen data sold in bulk on dark web markets as 'logs'.",references:[{title:"Infostealer Malware Analysis - MITRE ATT&CK",link:"https://attack.mitre.org/software/"},{title:"RedLine Stealer Technical Analysis Report",link:"https://www.cert.org.cn/"}],avoidances:["A0078","A0010","A0026","A0023","A0079"],directCauseRisks:["R0032","R0036","R0143","R0149"],indirectSupportRisks:[]},Pi={AT0064:Ci},Mi=Object.freeze(Object.defineProperty({__proto__:null,AT0064:Ci,default:Pi},Symbol.toStringTag,{value:"Module"})),ji={title:"Keyloggers",description:"A keylogger is a monitoring tool that records user keyboard input, used to steal passwords, credit card numbers, chat content, and other sensitive information. Keyloggers come in software and hardware types. Software keylogger implementations include API hooking (intercepting keyboard messages via SetWindowsHookEx), kernel-level drivers, form grabbing directly from browser form submissions, and screen recording assistance. Hardware keyloggers include USB interface devices and wireless keyboard signal interceptors. Modern keyloggers typically exist as functional modules within infostealers or may be embedded in legitimate software as spyware.",references:[{title:"Keylogger - MITRE ATT&CK T1056.001",link:"https://attack.mitre.org/techniques/T1056/001/"}]},Oi={AT0065:ji},Ii=Object.freeze(Object.defineProperty({__proto__:null,AT0065:ji,default:Oi},Symbol.toStringTag,{value:"Module"})),Bi={title:"Fake Apps",description:"Fake apps are malicious mobile applications that impersonate legitimate applications by mimicking the names, icons, and interface designs of well-known apps to deceive users into downloading and installing them, then implementing phishing, information theft, or backdoor implantation. Main characteristics include high-fidelity interfaces, permission abuse, malicious code implantation, push phishing, SMS interception on Android devices, and distribution through third-party app stores, phishing websites, and social media links.",references:[{title:"Fake Apps - Google Play Protect",link:"https://developers.google.com/android/play-protect"},{title:"Regulations on the Administration of Mobile Internet Application Information Services",link:"http://www.cac.gov.cn/"}]},xi={AT0066:Bi},zi=Object.freeze(Object.defineProperty({__proto__:null,AT0066:Bi,default:xi},Symbol.toStringTag,{value:"Module"})),Ei={title:"Malicious QR Code Generators",description:"Malicious QR code generators are tools for generating QR codes pointing to phishing pages, malicious download links, or malicious payment requests. They exploit users' inability to visually identify QR code content to commit fraud. Main attack methods include phishing QR codes, malicious download QR codes, payment hijacking QR codes, WiFi phishing QR codes, dynamic QR codes that can be remotely updated, and QR code overlay attacks replacing legitimate QR codes in shared bikes and parking payment scenarios.",references:[{title:"QR Code Security Risks - NIST",link:"https://www.nist.gov/publications"},{title:"QR Code Security Risks and Prevention",link:"https://www.cert.org.cn/"}]},Di={AT0067:Ei},Fi=Object.freeze(Object.defineProperty({__proto__:null,AT0067:Ei,default:Di},Symbol.toStringTag,{value:"Module"})),Hi={title:"Password Dictionaries/Rainbow Tables",description:"Password dictionaries and rainbow tables are pre-computed datasets used for password cracking and credential stuffing attacks. Password dictionaries are text collections containing common passwords, leaked passwords, and rule-generated passwords; rainbow tables are pre-computed mapping tables of hash values to plaintext passwords. Types include general password dictionaries, leaked password databases for credential stuffing, rule-generated dictionaries, social engineering dictionaries based on target personal information, rainbow tables for common hash algorithms (MD5, SHA1), and localized dictionaries. Representative tools include rockyou.txt, SecLists, and cracking tools like Hashcat and John the Ripper.",references:[{title:"Password Cracking - MITRE ATT&CK T1110",link:"https://attack.mitre.org/techniques/T1110/"},{title:"SecLists - OWASP",link:"https://github.com/danielmiessler/SecLists"}]},qi={AT0068:Hi},Wi=Object.freeze(Object.defineProperty({__proto__:null,AT0068:Hi,default:qi},Symbol.toStringTag,{value:"Module"})),Li={title:"Evil Twin WiFi",description:"Evil Twin WiFi is an attack tool that intercepts user network traffic and steals credentials by spoofing public WiFi hotspots. Attackers deploy malicious hotspots with the same or similar names as legitimate WiFi in public places (such as cafes, airports, and shopping malls), inducing users to connect and then conducting man-in-the-middle attacks. Main functions include hotspot spoofing, captive portal phishing, traffic interception, SSL stripping, DNS spoofing, and session hijacking. Representative tools include WiFi-Pumpkin, Fluxion, and Airgeddon.",references:[{title:"Evil Twin Attack - CISA",link:"https://www.cisa.gov/news-events/cybersecurity-advisories"},{title:"Public WiFi Security Risk Advisory - CNCERT",link:"https://www.cert.org.cn/"}]},Gi={AT0069:Li},Ui=Object.freeze(Object.defineProperty({__proto__:null,AT0069:Li,default:Gi},Symbol.toStringTag,{value:"Module"})),Ki={title:"Fraud-as-a-Service (FaaS) Platform",description:"Fraud-as-a-Service (FaaS) is a black market service model where cybercriminals tool and platform the entire fraud process, including pig butchering, investment fraud, and identity impersonation. Unlike AT0063 Phishing Toolkit which provides single-point phishing capabilities, FaaS platforms offer a complete fraud chain as a managed service from script generation, fake platform setup, victim screening, trust cultivation to money laundering. Key features and services include: ① Script libraries and training: providing multi-language, multi-scenario scam script templates and role-play training materials; ② Fake investment platform setup: providing customizable fake trading platform frontends and backend management systems supporting simulated trading quotes and fake profit displays; ③ Victim screening tools: identifying high-value potential victims through social media data crawling and analysis; ④ AI-assisted communication: integrating AI chatbots to assist or replace humans in daily communication and trust cultivation; ⑤ Payment channel integration: providing multi-channel fund reception and transfer solutions; ⑥ Money laundering service connections: seamlessly integrating with cryptocurrency mixers, underground banks, and other money laundering channels. FaaS platforms significantly lower the technical barriers and organizational costs of fraud, enabling non-professional criminal groups to conduct large-scale complex scams.",avoidances:["A0075","A0029","A0078"],directCauseRisks:["R0044","R0098","R0150"],indirectSupportRisks:[],references:[{title:"Chainalysis 2026 Crypto Crime Report",link:"https://www.chainalysis.com/"},{title:"UNODC Transnational Organized Fraud Report",link:"https://www.unodc.org/"}],updated:"2026-06-11"},Vi={AT0070:Ki},Ni=Object.freeze(Object.defineProperty({__proto__:null,AT0070:Ki,default:Vi},Symbol.toStringTag,{value:"Module"})),Qi={title:"Phishing-as-a-Service (PhaaS) Platform",description:"Phishing-as-a-Service (PhaaS) is a black market service model that provides complete phishing attack hosting. Unlike AT0063 Phishing Toolkit which provides downloadable phishing tools and templates, PhaaS platforms operate in a SaaS model where attackers don't need to set up their own servers, register domains, or configure email delivery systems. They simply pay subscription fees to access a full suite of services from phishing page hosting, email/SMS delivery, credential collection to two-factor authentication token theft. Key features include: ① Phishing page hosting: providing highly realistic login page hosting with automatic HTTPS certificate configuration and anti-detection mechanisms; ② Email/SMS delivery services: integrated email and SMS sending channels with capabilities to bypass spam filters; ③ Credential and token collection: real-time collection of victim-entered credentials and 2FA tokens, with some platforms supporting AiTM session hijacking; ④ Anti-detection and evasion: integrating CAPTCHA bypass, anti-bot mechanisms, domain rotation, and cloud service abuse techniques; ⑤ Analytics dashboard: providing data analysis, conversion rate statistics, and victim management for phishing campaigns. Representative platforms include EvilProxy and Storm-0443's PhaaS platform. PhaaS significantly lowers the technical barrier for phishing attacks, enabling non-technical personnel to launch large-scale high-quality phishing campaigns.",avoidances:["A0078","A0016"],directCauseRisks:["R0032","R0084","R0084-001","R0143"],indirectSupportRisks:[],references:[{title:"Proofpoint PhaaS Threat Report 2025",link:"https://www.proofpoint.com/"},{title:"Microsoft Digital Defense Report 2025",link:"https://www.microsoft.com/en-us/security/business/microsoft-digital-defense-report"}],updated:"2026-06-11"},Ji={AT0071:Qi},Yi=Object.freeze(Object.defineProperty({__proto__:null,AT0071:Qi,default:Ji},Symbol.toStringTag,{value:"Module"})),Zi={title:"AiTM Adversary-in-the-Middle Attack Tool",description:"Adversary-in-the-Middle (AiTM) attack tools are specifically designed to bypass multi-factor authentication (MFA) based on traditional man-in-the-middle attacks. Unlike AT0069 Fake WiFi which focuses on network-layer traffic interception, AiTM tools target application-layer authentication session interception and theft. Key features and attack methods include: ① Reverse proxy architecture: establishing a reverse proxy between the attacker-controlled server and the target website, forwarding requests and responses in real-time; ② Session token theft: when victims log in through the AiTM proxy, the tool steals post-authentication session cookies and tokens, enabling attackers to access victim accounts without passwords or MFA; ③ MFA bypass: since MFA verification completes normally during the proxy process, attackers obtain sessions that have already passed MFA verification, completely bypassing MFA protection; ④ Phishing page disguise: hosting AiTM proxy entry points on legitimate or similar domains to lure victims; ⑤ Session persistence: stolen session tokens can be used for extended periods, with some tools supporting automatic session refresh. Representative tools include Evilginx2 and Modlishka open-source frameworks. AiTM attacks have become one of the primary methods for stealing enterprise account credentials, and even MFA cannot effectively defend against them.",avoidances:["A0007-005","A0078","A0026"],directCauseRisks:["R0032","R0142","R0151"],indirectSupportRisks:[],references:[{title:"Microsoft Digital Defense Report 2025 - AiTM Phishing",link:"https://www.microsoft.com/en-us/security/business/microsoft-digital-defense-report"},{title:"CISA Guidance on AiTM Phishing Attacks",link:"https://www.cisa.gov/"}],updated:"2026-06-11"},Xi={AT0072:Zi},$i=Object.freeze(Object.defineProperty({__proto__:null,AT0072:Zi,default:Xi},Symbol.toStringTag,{value:"Module"})),ea={title:"Fake Call Spoofing Tool",description:"Fake call spoofing tools combine AI voice cloning technology with caller ID spoofing to disguise caller identity and voice during phone calls. Unlike AT0059 AI Voice Cloning Tool which only provides voice synthesis capabilities, fake call spoofing tools add telecom-level number forgery and call path manipulation capabilities. Key features and attack methods include: ① Caller ID spoofing: altering caller display numbers through VoIP gateways or SS7 signaling vulnerabilities, making the victim's phone display the real number of the target person or institution; ② AI real-time voice cloning: converting the attacker's voice to the target person's voice during calls in real-time, supporting two-way real-time dialogue; ③ Call scenario scripts: providing dialogue scripts and contingency response talking points for common scam scenarios; ④ Multi-line concurrent calling: supporting simultaneous spoofed calls to multiple targets for large-scale fraud; ⑤ Call recording and analysis: automatically recording call content for script improvement and subsequent extortion. This tool is key to the AI-driven evolution of telecom fraud, with global AI voice cloning fraud losses exceeding $400 billion in 2025.",avoidances:["A0084","A0086","A0073","A0027"],directCauseRisks:["R0084","R0095","R0120"],indirectSupportRisks:[],references:[{title:"Google Android Fake Call Detection Announcement",link:"https://blog.google/security/new-ai-powered-scam-detection-features/"},{title:"FCC Caller ID Authentication Rules",link:"https://www.fcc.gov/call-authentication"}],updated:"2026-06-11"},ta={AT0073:ea},ia=Object.freeze(Object.defineProperty({__proto__:null,AT0073:ea,default:ta},Symbol.toStringTag,{value:"Module"})),aa={title:"AI Agent Hijacking Tools",description:"Attack tools designed to hijack deployed AI agents. Unlike AT0057 LLM Automated Attack Tools which use LLMs to launch attacks, AI Agent Hijacking Tools target already deployed and running AI agents, forcing them to execute attacker-specified operations. Main capabilities and attack methods include: 1) Prompt injection hijacking: injecting carefully crafted prompts into AI agents to override original instructions and force execution of attacker-specified operations; 2) Tool call hijacking: manipulating an agent's tool invocation chain to call malicious tools or pass malicious parameters to legitimate tools; 3) Memory poisoning: tampering with an agent's memory or knowledge base to produce attacker-expected behaviors in subsequent interactions; 4) Privilege escalation: exploiting agent permission configuration vulnerabilities to gain system access beyond authorized scope; 5) Lateral movement: accessing other agents or system resources in the same environment through a hijacked agent. AI Agent hijacking is a novel attack method emerging with the widespread deployment of AI agents, posing a serious threat to enterprise AI automation systems.",avoidances:["A0087","A0089","A0079"],directCauseRisks:["R0032","R0148","R0149"],indirectSupportRisks:[],references:[{title:"Strengthening AI Agent Hijacking Evaluations",link:"https://www.nist.gov/news-events/news/2025/01/technical-blog-strengthening-ai-agent-hijacking-evaluations"},{title:"Fooling AI Agents: Web-Based Indirect Prompt Injection Observed in the Wild",link:"https://unit42.paloaltonetworks.com/ai-agent-prompt-injection/"},{title:"Agent Hijacking: How Prompt Injection Leads to Full AI System Compromise",link:"https://www.straiker.ai/blog/agent-hijacking-how-prompt-injection-leads-to-full-ai-system-compromise"}],updated:"2026-06-11"},oa={AT0074:aa},na=Object.freeze(Object.defineProperty({__proto__:null,AT0074:aa,default:oa},Symbol.toStringTag,{value:"Module"})),ra={title:"ClickFix Deception Tools",description:"ClickFix deception tools are a novel phishing tool that disguises itself as CAPTCHA repair or system update prompts to trick users into executing malicious PowerShell or CMD commands. Unlike AT0063 Phishing Toolkits which steal information through forged web pages, ClickFix exploits users' trust in system repair prompts, disguising malicious code execution as legitimate system operations. Main attack techniques include: 1) CAPTCHA repair disguise: displaying forged CAPTCHA display error prompts, claiming that repair commands need to be run for normal display; 2) Clipboard hijacking: copying malicious commands to the clipboard, guiding users to paste and execute them in a terminal or run dialog; 3) CAPTCHA bypass prompt: disguising as a CAPTCHA verification step, requiring users to execute specific commands to prove they are human; 4) Error page disguise: displaying forged browser error pages, prompting users to run repair scripts; 5) Multi-step induction: using multi-step interactive guidance to gradually lower user vigilance, ultimately tricking them into executing malicious code. ClickFix attacks were reported to have grown significantly by Proofpoint and other security vendors in 2025, and were listed as an emerging threat in the ENISA 2025 Threat Landscape Report.",avoidances:["A0051","A0078","A0016"],directCauseRisks:["R0028","R0084","R0154"],indirectSupportRisks:[],references:[{title:"Security Brief: ClickFix Social Engineering Technique Floods Threat Landscape",link:"https://www.proofpoint.com/us/blog/threat-insight/security-brief-clickfix-social-engineering-technique-floods-threat-landscape"},{title:"ClickFix: How to Infect Your PC in Three Easy Steps",link:"https://krebsonsecurity.com/2025/03/clickfix-how-to-infect-your-pc-in-three-easy-steps/"},{title:"Beyond The Click: Unveiling Fake CAPTCHA Campaigns",link:"https://www.splunk.com/en_us/blog/security/unveiling-fake-captcha-clickfix-attacks.html"}],updated:"2026-06-11"},sa={AT0075:ra},la=Object.freeze(Object.defineProperty({__proto__:null,AT0075:ra,default:sa},Symbol.toStringTag,{value:"Module"}));export{ue as $,zt as A,It as B,Mt as C,_t as D,Rt as E,At as F,bt as G,gt as H,ut as I,lt as J,nt as K,it as L,$e as M,Ye as N,Ne as O,Ue as P,We as Q,Fe as R,ze as S,Ie as T,Me as U,_e as V,Re as W,Ae as X,be as Y,ge as Z,la as _,na as a,le as a0,ne as a1,ie as a2,$ as a3,Y as a4,N as a5,U as a6,W as a7,F as a8,z as a9,I as aa,M as ab,_ as ac,R as ad,A as ae,b as af,g as ag,u as ah,l as ai,n as aj,i as ak,ia as b,$i as c,Yi as d,Ni as e,Ui as f,Wi as g,Fi as h,zi as i,Ii as j,Mi as k,_i as l,Ri as m,Ai as n,bi as o,gi as p,ui as q,li as r,ni as s,ii as t,$t as u,Yt as v,Nt as w,Ut as x,Wt as y,Ft as z};
